const to565 = ([r, g, b]) => ((r >> 3) << 11) | ((g >> 2) << 5) | (b >> 3);

const hexRgb = (s) => {
  const h = s.replace("#", "");
  return [0, 2, 4].map((i) => parseInt(h.slice(i, i + 2), 16));
};

const mix = (a, b, t) => a.map((v, i) => Math.round(v + (b[i] - v) * t));

// Role order from firmware/tools/gen/ui/themes.py:
// bg, fg, hi, dim, dimmer, warn, crit, ink, blush.
function derive(colors) {
  const surface = hexRgb(colors.surface);
  const ink = hexRgb(colors.ink);
  const hi = colors.accent ? hexRgb(colors.accent) : ink;
  const roles = [surface, ink, hi, mix(ink, surface, 0.45), mix(ink, surface, 0.72),
                 [230, 150, 40], [200, 70, 66], ink, [252, 176, 184]];
  return roles.map(to565);
}

export const isAll = (value) =>
  value === "all" || (Array.isArray(value) && value.length === 1 && value[0] === "all");

const enabled = (value) => (isAll(value) ? [] : value || []);

function tzMinutes(value) {
  if (value == null) return 0;
  if (typeof value === "number") return Math.trunc(value);

  let s = String(value).trim();
  if (!s) return 0;
  let sign = 1;
  if (s[0] === "+" || s[0] === "-") {
    sign = s[0] === "-" ? -1 : 1;
    s = s.slice(1);
  }
  const [hh, mm] = s.split(":");
  return sign * (parseInt(hh, 10) * 60 + (mm ? parseInt(mm, 10) : 0));
}

export function fromManifest(manifest) {
  const brand = manifest.brand || {};
  const device = manifest.device || {};
  const theme = device.theme || {};
  const typeface = device.typeface || {};
  const mascot = device.mascot || {};

  const config = {
    brand: {
      name: brand.name || "",
      tagline: brand.tagline || "",
      website: brand.website || "",
      mascot: brand.mascot || "",
    },
    defaults: {
      theme: theme.default || "",
      typeface: typeface.default || "",
      mascot: mascot.default || "",
      mood: mascot.mood || "happy",
      tz: tzMinutes(device.timezone),
    },
    enabled: {
      games: enabled((device.games || {}).enabled),
      apps: enabled((device.apps || {}).enabled),
      packs: enabled(mascot.enabled),
      themes: enabled(theme.enabled),
      typefaces: enabled(typeface.enabled),
    },
  };

  const customs = (theme.custom || [])
    .filter((c) => c.name && c.colors)
    .map((c) => ({ name: c.name, colors: derive(c.colors) }));
  if (customs.length) config.themes = customs;

  return config;
}

export function encode(config) {
  const body = new TextEncoder().encode(JSON.stringify(config));
  const buf = new Uint8Array(6 + body.length);
  buf[0] = 0x54; buf[1] = 0x4d; buf[2] = 0x47; buf[3] = 0x31;
  buf[4] = body.length & 0xff;
  buf[5] = (body.length >> 8) & 0xff;
  buf.set(body, 6);
  return buf;
}
